total = 0
for p in PAGINAS:
    html = gerar_html(p)
    out = pt_dir / f"{p['slug']}.html"
    with open(out, "w", encoding="utf-8") as f:
        f.write(html)
    print(f"✅ /pt/{p['slug']}.html")
    total += 1

print(f"\n🎉 {total} páginas geradas em /pt/")
